import { execSync } from 'node:child_process';
import { existsSync, readFileSync } from 'node:fs';
import { join } from 'node:path';

/**
 * Safely execute a shell command and return its stdout, or empty string on failure.
 */
// shell required: safeExec accepts arbitrary command strings that may contain pipes, redirects, or globs
export function safeExec(cmd: string, cwd: string, timeoutMs = 5000): string {
  try {
    return execSync(cmd, {
      cwd,
      encoding: 'utf8',
      timeout: timeoutMs,
      stdio: ['pipe', 'pipe', 'pipe'],
    }).trim();
  } catch {
    return '';
  }
}

/**
 * Read and parse package.json from a project directory, or null on failure.
 */
export function readPackageJson(projectDir: string): Record<string, unknown> | null {
  const pkgPath = join(projectDir, 'package.json');
  if (!existsSync(pkgPath)) return null;
  try {
    return JSON.parse(readFileSync(pkgPath, 'utf8'));
  } catch {
    return null;
  }
}

/**
 * Check if any of the given config files exist in projectDir.
 */
export function findFirstConfig(projectDir: string, candidates: string[]): string | null {
  for (const config of candidates) {
    if (existsSync(join(projectDir, config))) return config;
  }
  return null;
}
