import { existsSync } from 'node:fs';
import { join } from 'node:path';
import type { HookInput, HookResult , HookContext} from '../types.js';
import { outputSilentSuccess, outputWithContext } from '../lib/common.js';
import { safeExec, readPackageJson, findFirstConfig } from './context-loader-utils.js';
import { NOOP_CTX } from '../lib/context.js';

/**
 * Repo Structure Indexer — builds lightweight repo map.
 * Used by: explore skill (PreToolUse/Glob, once:true)
 */
export function repoStructureIndexer(_input: HookInput, hookCtx: HookContext = NOOP_CTX): HookResult {
  const projectDir = hookCtx.projectDir;

  const tree = safeExec(
    'find . -maxdepth 2 -type d -not -path "*/node_modules/*" -not -path "*/.git/*" | head -40',
    projectDir,
  );
  const pkg = readPackageJson(projectDir);
  const deps = pkg?.dependencies
    ? Object.keys(pkg.dependencies as Record<string, string>).slice(0, 15).join(', ')
    : '';
  const fileCount = safeExec(
    'find . -type f -not -path "*/node_modules/*" -not -path "*/.git/*" | wc -l',
    projectDir,
  );

  const ctx = [
    '[Repo Structure — loaded once]',
    `Files: ${fileCount.trim()}`,
    deps ? `Dependencies: ${deps}` : '',
    tree ? `\nDirectory tree (depth 2):\n${tree}` : '',
  ].filter(Boolean).join('\n');

  return outputWithContext(ctx);
}

/**
 * Test Framework Detector — identifies test tooling.
 * Used by: verify skill (PreToolUse/Bash, once:true)
 */
export function testFrameworkDetector(_input: HookInput, hookCtx: HookContext = NOOP_CTX): HookResult {
  const projectDir = hookCtx.projectDir;
  const frameworks: string[] = [];

  const pkg = readPackageJson(projectDir);
  if (pkg) {
    const allDeps = {
      ...(pkg.dependencies as Record<string, string> || {}),
      ...(pkg.devDependencies as Record<string, string> || {}),
    };
    if (allDeps.vitest) frameworks.push('vitest');
    if (allDeps.jest) frameworks.push('jest');
    if (allDeps.mocha) frameworks.push('mocha');
    if (allDeps.playwright) frameworks.push('playwright');
    if (allDeps.cypress) frameworks.push('cypress');
  }

  if (existsSync(join(projectDir, 'pytest.ini')) || existsSync(join(projectDir, 'pyproject.toml'))) {
    frameworks.push('pytest');
  }
  if (existsSync(join(projectDir, 'go.mod'))) frameworks.push('go test');

  if (!frameworks.length) return outputSilentSuccess();

  const testScript = pkg?.scripts
    ? (pkg.scripts as Record<string, string>).test || ''
    : '';

  const ctx = [
    '[Test Framework — loaded once]',
    `Frameworks: ${frameworks.join(', ')}`,
    testScript ? `Test command: npm test -> ${testScript}` : '',
  ].filter(Boolean).join('\n');

  return outputWithContext(ctx);
}

/**
 * Project Convention Loader — detects code style conventions.
 * Used by: implement skill (PreToolUse/Write, once:true)
 */
export function projectConventionLoader(_input: HookInput, hookCtx: HookContext = NOOP_CTX): HookResult {
  const projectDir = hookCtx.projectDir;
  const conventions: string[] = [];

  const linter = findFirstConfig(projectDir, [
    '.eslintrc.json', '.eslintrc.js', 'eslint.config.js', 'eslint.config.mjs', 'biome.json',
  ]);
  if (linter) conventions.push(`Linter: ${linter}`);
  if (existsSync(join(projectDir, 'tsconfig.json'))) conventions.push('TypeScript project');

  const hasBarrels = safeExec(
    'find src -name "index.ts" -maxdepth 3 2>/dev/null | head -3',
    projectDir,
  );
  if (hasBarrels) conventions.push('Uses barrel exports (index.ts)');

  if (!conventions.length) return outputSilentSuccess();

  const ctx = ['[Project Conventions — loaded once]', ...conventions].join('\n');
  return outputWithContext(ctx);
}

