/**
 * Setup Env Detector — detects project stack for onboarding.
 * Used by: setup skill (PreToolUse/Bash, once:true)
 */
export function setupEnvDetector(_input: HookInput, hookCtx: HookContext = NOOP_CTX): HookResult {
  const projectDir = hookCtx.projectDir;
  const stack: string[] = [];

  if (existsSync(join(projectDir, 'package.json'))) stack.push('Node.js');
  if (existsSync(join(projectDir, 'tsconfig.json'))) stack.push('TypeScript');
  if (existsSync(join(projectDir, 'pyproject.toml')) || existsSync(join(projectDir, 'requirements.txt'))) stack.push('Python');
  if (existsSync(join(projectDir, 'go.mod'))) stack.push('Go');
  if (existsSync(join(projectDir, 'Cargo.toml'))) stack.push('Rust');
  if (existsSync(join(projectDir, 'Dockerfile'))) stack.push('Docker');
  if (existsSync(join(projectDir, '.github/workflows'))) stack.push('GitHub Actions');

  const ctx = [
    '[Stack Detection — loaded once]',
    `Detected: ${stack.join(', ') || 'unknown'}`,
    `Project root: ${projectDir}`,
  ].join('\n');

  return outputWithContext(ctx);
}

