/**
 * Context Publisher - SubagentStop Hook
 * CC 2.1.7 Compliant: includes continue field in all outputs
 *
 * Publishes agent decisions to context (Context Protocol 2.0).
 *
 * Version: 1.0.0 (TypeScript port)
 */

import { existsSync, mkdirSync, readFileSync } from 'node:fs';
import { atomicWriteSync } from '../lib/atomic-write.js';
import { dirname } from 'node:path';
import type { HookInput, HookResult , HookContext} from '../types.js';
import { outputSilentSuccess, getProjectDir } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

// -----------------------------------------------------------------------------
// Path Helpers
// -----------------------------------------------------------------------------

function getDecisionsFile(): string {
  return `${getProjectDir()}/.claude/context/knowledge/decisions/active.json`;
}

function getSessionState(): string {
  return `${getProjectDir()}/.claude/context/session/state.json`;
}

// -----------------------------------------------------------------------------
// Helper Functions
// -----------------------------------------------------------------------------

interface DecisionEntry {
  timestamp: string;
  agent: string;
  summary: string;
  status: string;
}

interface DecisionsFile {
  schema_version: string;
  decisions: Record<string, DecisionEntry>;
}

interface TaskEntry {
  agent: string;
  timestamp: string;
  summary: string;
}

interface SessionState {
  schema_version: string;
  session_id: string;
  started_at: string;
  last_activity: string;
  active_agent: string | null;
  tasks_pending: string[];
  tasks_completed: TaskEntry[];
}

function ensureDir(dirPath: string): void {
  try {
    mkdirSync(dirPath, { recursive: true });
  } catch {
    // Ignore
  }
}

function readJsonFile<T>(filePath: string, defaultValue: T): T {
  if (!existsSync(filePath)) {
    return defaultValue;
  }
  try {
    return JSON.parse(readFileSync(filePath, 'utf8')) as T;
  } catch {
    return defaultValue;
  }
}

function writeJsonFile(filePath: string, data: unknown): void {
  const dir = dirname(filePath);
  ensureDir(dir);
  try {
    atomicWriteSync(filePath, JSON.stringify(data, null, 2));
  } catch {
    // Ignore
  }
}

// -----------------------------------------------------------------------------
// Constants
// -----------------------------------------------------------------------------

/** Maximum completed tasks to retain in session state */
const MAX_COMPLETED_TASKS = 50;

// -----------------------------------------------------------------------------
// Hook Implementation
// -----------------------------------------------------------------------------

export function contextPublisher(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const agentName = input.subagent_type || input.agent_type || 'unknown';
  const timestamp = new Date().toISOString();

  // Read agent output from input
  const output = input.agent_output || input.output || '';

  // Extract summary from output (first 200 chars)
  let summary = output.substring(0, 200);
  if (output.length > 200) {
    summary += '...';
  }

  // Skip recording empty/unknown task entries — they bloat state.json
  const hasContent = agentName !== 'unknown' || summary.trim().length > 0;

  // Create agent key (replace hyphens with underscores for JSON)
  const agentKey = agentName.replace(/-/g, '_');

  // === Update Decisions File (Context Protocol 2.0) ===
  // Only write decisions for identified agents with output
  if (hasContent) {
    const decisionsFile = getDecisionsFile();
    const decisionsDir = dirname(decisionsFile);
    ensureDir(decisionsDir);

    const defaultDecisions: DecisionsFile = {
      schema_version: '2.0.0',
      decisions: {},
    };

    const decisions = readJsonFile(decisionsFile, defaultDecisions);

    // Ensure decisions object exists (defensive against old schema versions)
    if (!decisions.decisions || typeof decisions.decisions !== 'object') {
      decisions.decisions = {};
    }

    const decisionEntry: DecisionEntry = {
      timestamp,
      agent: agentName,
      summary,
      status: 'completed',
    };

    decisions.decisions[agentKey] = decisionEntry;
    writeJsonFile(decisionsFile, decisions);
  }

  // === Update Session State (Context Protocol 2.0) ===
  const sessionStateFile = getSessionState();
  const sessionDir = dirname(sessionStateFile);
  ensureDir(sessionDir);

  const defaultState: SessionState = {
    schema_version: '2.0.0',
    session_id: '',
    started_at: timestamp,
    last_activity: timestamp,
    active_agent: null,
    tasks_pending: [],
    tasks_completed: [],
  };

  const sessionState = readJsonFile(sessionStateFile, defaultState);

  // Ensure arrays exist (defensive against old schema versions)
  if (!Array.isArray(sessionState.tasks_completed)) {
    sessionState.tasks_completed = [];
  }
  if (!Array.isArray(sessionState.tasks_pending)) {
    sessionState.tasks_pending = [];
  }

  // Only record tasks with meaningful content (fixes #449: empty entries bloat)
  if (hasContent) {
    const taskEntry: TaskEntry = {
      agent: agentName,
      timestamp,
      summary,
    };

    sessionState.tasks_completed.push(taskEntry);

    // Cap array size — keep most recent entries (fixes #449: unbounded growth)
    if (sessionState.tasks_completed.length > MAX_COMPLETED_TASKS) {
      sessionState.tasks_completed = sessionState.tasks_completed.slice(-MAX_COMPLETED_TASKS);
    }
  }

  sessionState.last_activity = timestamp;
  sessionState.active_agent = null;

  writeJsonFile(sessionStateFile, sessionState);

  // === Logging ===
  const logDir = ctx.logDir;
  ensureDir(logDir);

  const dateStr = new Date().toISOString().replace(/[-:]/g, '').substring(0, 15);
  const logFile = `${logDir}/${agentName}_${dateStr}.log`;

  const logContent = `=== CONTEXT PUBLICATION (Protocol 2.0) ===
Agent: ${agentName}
Timestamp: ${timestamp}
Decisions file: ${getDecisionsFile()}
Session state: ${sessionStateFile}

=== AGENT OUTPUT ===
${output}
`;

  try {
    atomicWriteSync(logFile, logContent);
  } catch {
    // Ignore
  }

  return outputSilentSuccess();
}
