/**
 * Handoff Writer — Stop Hook
 *
 * Writes .claude/HANDOFF.md with structured session context on stop.
 * This is the WRITE half of the save/restore loop.
 * The READ half is prompt/handoff-injector.ts (UserPromptSubmit).
 *
 * Uses:
 * - input.last_assistant_message (CC 2.1.47+) for session summary
 * - git diff for modified files
 * - decisions.jsonl for recent decisions
 * - task-completions.jsonl for open tasks
 * - learning-extractor for structured classification
 */

import { existsSync, readFileSync, mkdirSync } from 'node:fs';
import { execFileSync } from 'node:child_process';
import { join } from 'node:path';
import type { HookInput, HookResult , HookContext} from '../types.js';
import {
  outputSilentSuccess,
} from '../lib/common.js';
import { extractLearnings, formatLearnings } from '../lib/learning-extractor.js';
import { atomicWriteSync } from '../lib/atomic-write.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'handoff-writer';

/**
 * Get files modified in the working tree
 */
function getModifiedFiles(projectDir: string): string[] {
  try {
    const output = execFileSync('git', ['diff', '--name-only', 'HEAD'], {
      encoding: 'utf8',
      timeout: 3000,
      cwd: projectDir,
      stdio: ['pipe', 'pipe', 'pipe'],
    });
    return output.trim().split('\n').filter(Boolean).slice(0, 30);
  } catch {
    return [];
  }
}

/**
 * Get recent decisions from decisions.jsonl
 */
function getRecentDecisions(projectDir: string): string[] {
  const file = join(projectDir, '.claude', 'logs', 'decisions.jsonl');
  if (!existsSync(file)) return [];

  try {
    const lines = readFileSync(file, 'utf8').trim().split('\n').filter(Boolean);
    return lines.slice(-8).map(line => {
      try {
        const entry = JSON.parse(line);
        return entry.summary || entry.decision || '';
      } catch {
        return '';
      }
    }).filter(Boolean);
  } catch {
    return [];
  }
}

/**
 * Get recent tasks from task-completions.jsonl
 */
function getRecentTasks(projectDir: string): string[] {
  const file = join(projectDir, '.claude', 'logs', 'task-completions.jsonl');
  if (!existsSync(file)) return [];

  try {
    const lines = readFileSync(file, 'utf8').trim().split('\n').filter(Boolean);
    return lines.slice(-8).map(line => {
      try {
        const entry = JSON.parse(line);
        return `${entry.task_subject || 'untitled'} [${entry.task_status || 'unknown'}]`;
      } catch {
        return '';
      }
    }).filter(Boolean);
  } catch {
    return [];
  }
}

/**
 * Extract a concise summary from the last assistant message.
 * Takes the first ~600 chars, breaking at a sentence boundary.
 */
function extractSummary(lastMessage: string): string {
  if (!lastMessage) return 'No summary available.';

  // Take first 800 chars then cut at last sentence boundary
  const truncated = lastMessage.substring(0, 800);
  const sentenceEnd = truncated.lastIndexOf('. ');
  if (sentenceEnd > 200) {
    return truncated.substring(0, sentenceEnd + 1);
  }
  // Fall back to first 600 chars with ellipsis
  return truncated.substring(0, 600) + (lastMessage.length > 600 ? '...' : '');
}

/**
 * Handoff writer — Stop hook that writes .claude/HANDOFF.md
 */
export function handoffWriter(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  try {
    const projectDir = input.project_dir || (ctx.projectDir);
    const claudeDir = join(projectDir, '.claude');
    const handoffPath = join(claudeDir, 'HANDOFF.md');

    // Ensure .claude/ exists
    if (!existsSync(claudeDir)) {
      mkdirSync(claudeDir, { recursive: true });
    }

    const branch = ctx.branch;
    const sessionId = input.session_id || (ctx.sessionId);
    const now = `${new Date().toISOString().replace('T', ' ').slice(0, 19)} UTC`;
    const lastMessage = input.last_assistant_message || '';

    // Gather data
    const modifiedFiles = getModifiedFiles(projectDir);
    const decisions = getRecentDecisions(projectDir);
    const tasks = getRecentTasks(projectDir);
    const summary = extractSummary(lastMessage);

    // Extract structured learnings from assistant message
    const learnings = extractLearnings(lastMessage);
    const learningsMd = formatLearnings(learnings);

    // Build HANDOFF.md
    const sections: string[] = [
      `# Session Handoff`,
      '',
      `**Branch**: ${branch}`,
      `**When**: ${now}`,
      `**Session**: ${sessionId}`,
      '',
      `## Summary`,
      summary,
    ];

    if (modifiedFiles.length > 0) {
      sections.push('', `## Modified Files`, modifiedFiles.map(f => `- ${f}`).join('\n'));
    }

    if (learningsMd) {
      sections.push('', learningsMd);
    } else if (decisions.length > 0) {
      // Fallback to raw decisions if learning extractor found nothing
      sections.push('', `## Decisions Made`, decisions.map(d => `- ${d}`).join('\n'));
    }

    if (tasks.length > 0) {
      sections.push('', `## Recent Tasks`, tasks.map(t => `- ${t}`).join('\n'));
    }

    const content = `${sections.join('\n')}\n`;
    atomicWriteSync(handoffPath, content);

    ctx.log(HOOK_NAME, `Wrote ${handoffPath} (${content.length} chars, ${modifiedFiles.length} files, ${learnings.length} learnings)`);
  } catch (error) {
    const msg = error instanceof Error ? error.message : String(error);
    ctx.log(HOOK_NAME, `Failed to write handoff: ${msg}`, 'warn');
  }

  return outputSilentSuccess();
}
