/**
 * TaskCreated Hook: Progress Initializer
 *
 * Detects numbered task creation patterns (e.g., [1/5]) and initializes the progress
 * tracker state so the progress bar renders correctly from the first task completion.
 *
 * Works in tandem with task-completed/task-progress-tracker.ts which renders the bar.
 *
 * @hook TaskCreated
 * @since CC 2.1.84
 */

import { existsSync, readFileSync, mkdirSync } from 'node:fs';
import { dirname, join } from 'node:path';
import type { HookInput, HookResult , HookContext} from '../types.js';
import { outputSilentSuccess, logHook } from '../lib/common.js';
import { atomicWriteSync } from '../lib/atomic-write.js';
import { getLogDir } from '../lib/paths.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'task-progress-initializer';

interface ProgressState {
  total: number;
  completed: number;
  task_ids: string[];
  session_id: string;
}

function getStatePath(): string {
  return join(getLogDir(), 'task-progress-state.json');
}

function loadState(sessionId: string): ProgressState {
  try {
    const path = getStatePath();
    if (existsSync(path)) {
      const parsed = JSON.parse(readFileSync(path, 'utf8')) as Partial<ProgressState>;
      if (!Array.isArray(parsed.task_ids)) throw new Error('invalid shape');
      if (parsed.session_id && parsed.session_id !== sessionId) {
        return { total: 0, completed: 0, task_ids: [], session_id: sessionId };
      }
      return { total: parsed.total ?? 0, completed: parsed.completed ?? 0, task_ids: parsed.task_ids, session_id: sessionId };
    }
  } catch { /* start fresh */ }
  return { total: 0, completed: 0, task_ids: [], session_id: sessionId };
}

function saveState(state: ProgressState): void {
  try {
    const path = getStatePath();
    const dir = dirname(path);
    mkdirSync(dir, { recursive: true });
    atomicWriteSync(path, JSON.stringify(state));
  } catch {
    logHook(HOOK_NAME, 'Failed to persist state', 'warn');
  }
}

export function taskProgressInitializer(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const taskSubject = input.task_subject || '';
  const sessionId = input.session_id || '';

  if (!taskSubject) return outputSilentSuccess();

  // Detect numbered task format: [1/7] or [N/M]
  const numberMatch = taskSubject.match(/^\[(\d+)\/(\d+)\]/);
  if (!numberMatch) return outputSilentSuccess();

  const total = parseInt(numberMatch[2], 10);
  if (total < 2) return outputSilentSuccess();

  const state = loadState(sessionId);

  // Update total if this batch is larger
  if (total > state.total) {
    state.total = total;
    saveState(state);
    ctx.log(HOOK_NAME, `Initialized progress: 0/${total} tasks`);
  }

  return outputSilentSuccess();
}
