/**
 * CwdChanged Hook — Reload project context on directory change
 *
 * CC 2.1.83: Fires when working directory changes. Returns updated
 * watchPaths list and injects refreshed project context.
 *
 * @hook CwdChanged
 * @since CC 2.1.83
 * @see #1229
 */

import type { HookInput, HookResult , HookContext} from '../types.js';
import { outputSilentSuccess, getPluginRoot } from '../lib/common.js';
import { existsSync, readdirSync, readFileSync } from 'node:fs';
import { join } from 'node:path';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'cwd-changed';

/** Files to watch for changes in the new directory */
function getWatchPaths(projectDir: string): string[] {
  const candidates = [
    '.claude/rules',
    'CLAUDE.md',
    'package.json',
    '.env',
    '.claude/settings.json',
  ];
  return candidates
    .map(f => join(projectDir, f))
    .filter(p => existsSync(p));
}

// -----------------------------------------------------------------------------
// Skill path_patterns matching (Candlekeep #1228)
// -----------------------------------------------------------------------------

/** Cache the skill → path_patterns index (built once per process) */
let skillPathIndex: Array<{ skill: string; patterns: string[] }> | null = null;

/** @internal Reset cache for testing */
export function _resetSkillPathIndex(): void { skillPathIndex = null; }

/**
 * Build an index of skill name → path_patterns from SKILL.md frontmatter.
 * Cached across invocations within the same process.
 */
function getSkillPathIndex(): Array<{ skill: string; patterns: string[] }> {
  if (skillPathIndex) return skillPathIndex;
  skillPathIndex = [];

  const pluginRoot = getPluginRoot();
  if (!pluginRoot) return skillPathIndex;

  const skillsDir = join(pluginRoot, 'skills');
  if (!existsSync(skillsDir)) return skillPathIndex;

  try {
    for (const entry of readdirSync(skillsDir)) {
      const skillMd = join(skillsDir, entry, 'SKILL.md');
      if (!existsSync(skillMd)) continue;

      try {
        const content = readFileSync(skillMd, 'utf8');
        const fmMatch = content.match(/^---\n([\s\S]*?)\n---/);
        if (!fmMatch) continue;

        const ppMatch = fmMatch[1].match(/^path_patterns:\s*\[(.+)\]$/m);
        if (!ppMatch) continue;

        const patterns = ppMatch[1]
          .split(',')
          .map(s => s.trim().replace(/^["']|["']$/g, ''));

        if (patterns.length > 0) {
          skillPathIndex.push({ skill: entry, patterns });
        }
      } catch {
        // Skip unreadable skills
      }
    }
  } catch {
    // Skills dir unreadable
  }

  return skillPathIndex;
}

/**
 * Collect file/directory names at up to 2 levels of depth.
 * Level 0: project root. Level 1: common subdirectories.
 * Skips heavy directories (node_modules, .git, dist, build, vendor).
 * Cap total entries at 200 to bound scan time.
 */
const SKIP_DIRS = new Set(['node_modules', '.git', 'dist', 'build', 'vendor', '__pycache__', '.next', '.cache']);

function collectEntries(dir: string): Set<string> {
  const names = new Set<string>();
  try {
    const level0 = readdirSync(dir);
    for (const entry of level0) {
      names.add(entry);
      if (names.size >= 200) return names;

      // Scan one level deeper for non-skipped directories
      if (!SKIP_DIRS.has(entry) && !entry.startsWith('.')) {
        try {
          const subPath = join(dir, entry);
          const level1 = readdirSync(subPath);
          for (const sub of level1) {
            names.add(sub);
            if (names.size >= 200) return names;
          }
        } catch {
          // Not a directory or unreadable — skip
        }
      }
    }
  } catch {
    // Root unreadable
  }
  return names;
}

/**
 * Match directory contents against skill path_patterns.
 * Scans 2 levels deep to catch nested directories like src/migrations/.
 * Returns skill names whose patterns match files in the directory.
 */
function matchSkillsByDirectory(dir: string): string[] {
  const index = getSkillPathIndex();
  if (index.length === 0) return [];

  const entries = collectEntries(dir);
  if (entries.size === 0) return [];

  const matched = new Set<string>();
  for (const { skill, patterns } of index) {
    for (const pattern of patterns) {
      // Strip **/ prefix/suffix for directory name matching
      const base = pattern.replace(/\*\*\//g, '').replace(/\/\*\*/g, '');
      if (base.includes('*')) {
        // Convert glob to regex: * → [^/]*, . → \., rest literal
        const re = new RegExp(
          `^${base.replace(/\./g, '\\.').replace(/\*/g, '[^/]*')}$`,
        );
        for (const e of entries) {
          if (re.test(e)) {
            matched.add(skill);
            break;
          }
        }
      } else {
        // Exact directory or file name: migrations, prisma, k8s
        if (entries.has(base)) {
          matched.add(skill);
        }
      }
      if (matched.has(skill)) break;
    }
  }

  return [...matched].sort();
}

export function cwdChanged(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const oldCwd = input.old_cwd || '';
  const newCwd = input.new_cwd || '';

  if (!newCwd) {
    return outputSilentSuccess();
  }

  ctx.log(HOOK_NAME, `Directory changed: ${oldCwd} → ${newCwd}`);

  const watchPaths = getWatchPaths(newCwd);

  // Detect project type from new directory
  const signals: string[] = [];
  if (existsSync(join(newCwd, 'package.json'))) signals.push('Node.js');
  if (existsSync(join(newCwd, 'pyproject.toml')) || existsSync(join(newCwd, 'requirements.txt'))) signals.push('Python');
  if (existsSync(join(newCwd, 'go.mod'))) signals.push('Go');
  if (existsSync(join(newCwd, 'Cargo.toml'))) signals.push('Rust');
  if (existsSync(join(newCwd, 'Gemfile'))) signals.push('Ruby');
  if (existsSync(join(newCwd, 'terraform'))) signals.push('Terraform');

  const techStack = signals.length > 0 ? signals.join(', ') : 'unknown';

  // Match skills by path_patterns (#1228)
  const relevantSkills = matchSkillsByDirectory(newCwd);
  const skillHint = relevantSkills.length > 0
    ? ` | Relevant skills: ${relevantSkills.map(s => `/ork:${s}`).join(', ')}`
    : '';

  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: {
      additionalContext: `[CwdChanged] New directory: ${newCwd} | Stack: ${techStack}${skillHint}`,
      watchPaths,
    },
  } as HookResult;
}
